900	            if ar.currentline > 0 {
901	                let zero = ar
902	                    .short_src
903	                    .iter()
904	                    .position(|&b| b == 0)
905	                    .unwrap_or(ar.short_src.len());
906	                let mut buf: Vec<u8> = ar.short_src[..zero].to_vec();
907	                buf.push(b':');
908	                buf.extend_from_slice(ar.currentline.to_string().as_bytes());
909	                buf.extend_from_slice(b": ");
910	                lua_vm::api::push_lstring(self, &buf)?;
911	                return Ok(());
912	            }
913	        }
914	        lua_vm::api::push_lstring(self, b"")?;
915	        Ok(())
916	    }
